#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        double chef=0.0, chefu=0.0;
        for(int i=0;i<N;i++){
            double G, A, B; scanf("%lf %lf %lf", &G, &A, &B);
            double denom = A + B;
            chef += G * B / denom;
            chefu += G * A / denom;
        }
        printf("%.10f %.10f\n", chef, chefu);
    }
    return 0;
}

