import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = fs.nextInt();
            double chef = 0.0, chefu = 0.0;
            for (int i = 0; i < N; i++) {
                double G = fs.nextDouble();
                double A = fs.nextDouble();
                double B = fs.nextDouble();
                double denom = A + B;
                chef += G * B / denom;
                chefu += G * A / denom;
            }
            sb.append(String.format(Locale.US, "%.10f %.10f\n", chef, chefu));
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { return (int) nextLong(); }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        double nextDouble() throws IOException { return Double.parseDouble(next()); }
        String next() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            StringBuilder sb = new StringBuilder();
            while (c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

